raw_snippet:
JSON_INPUT="${JSON_INPUT:-}" TEMPLATE="${TEMPLATE:-}" BATCH_FILE="${BATCH_FILE:-}" CHAT_MODE="${CHAT_MODE:-0}" SET_DEFAULT_MODEL="${SET_DEFAULT_MODEL:-}"
LIST_MODELS="${LIST_MODELS:-0}" LIST_PROVIDERS="${LIST_PROVIDERS:-0}" FORCE_SAVE_MODE="${FORCE_SAVE_MODE:-}" OUT_PATH="${OUT_PATH:-}"
DRY_RUN="${DRY_RUN:-0}" STREAM_MODE="${STREAM_MODE:-0}" QUIET="${QUIET:-0}" INSTALL_EXTRAS="${INSTALL_EXTRAS:-0}" DEBUG="${DEBUG:-0}"
PROVIDER_CLI="${PROVIDER_CLI:-}" PROVIDER_INTERACTIVE="${PROVIDER_INTERACTIVE:-0}"
SHOW_CONFIG="${SHOW_CONFIG:-0}" DIAGNOSTICS="${DIAGNOSTICS:-0}"
FILE_INPUTS=() ARGS=() OUTPUT_MODE="${OUTPUT_MODE:-text}"
MODEL_CLI_SET="${MODEL_CLI_SET:-0}"
INSTALL_EXTRAS_SRC=""
BOOTSTRAP_ONLY="${BOOTSTRAP_ONLY:-0}"

while [ $# -gt 0 ]; do
  case "$1" in
    --refresh-models|--refresh-model) REFRESH_MODELS=1; shift ;;
    --list-models) LIST_MODELS=1; shift ;;
    --list-providers) LIST_PROVIDERS=1; shift ;;
    --list-providers-raw) LIST_PROVIDERS_RAW=1; shift ;;
    --list-models-raw) LIST_MODELS_RAW=1; shift ;;
    --set-default) SET_DEFAULT_MODEL="${2:-}"; shift 2 ;;
    -m|--model) MODEL="${2:-}"; MODEL_CLI_SET=1; shift 2 ;;
    -f) FILE_INPUTS+=("${2:-}"); shift 2 ;;
    --json-input) JSON_INPUT="${2:-}"; shift 2 ;;
    --template) TEMPLATE="${2:-}"; shift 2 ;;
    --batch) BATCH_FILE="${2:-}"; shift 2 ;;
    --session)
      # opt-in session id
      SESSION_ID="${2:-}"
      if [ -n "$SESSION_ID" ] && [ "${SESSION_ID:0:1}" != "-" ]; then
        shift 2
      else
        log_error "ARGS" "--session requires an argument"
        exit "$GROQBASHERRTMP"
      fi
      ;;
    --session-window)
      SESSION_WINDOW="${2:-}"
      if [ -n "$SESSION_WINDOW" ] && [ "${SESSION_WINDOW:0:1}" != "-" ]; then
        shift 2
      else
        # allow --session-window without value -> default 10
        SESSION_WINDOW="10"
        shift
      fi
      ;;
    --system) SYSTEM_PROMPT="${2:-}"; shift 2 ;;
    --ture) TURE="${2:-}"; shift 2 ;;
    --temperature) TURE="${2:-}"; shift 2 ;;
    --max) MAX_TOKENS="${2:-}"; shift 2 ;;
    --debug) DEBUG=1; shift ;;
    --save) FORCE_SAVE_MODE="save"; shift ;;
    --nosave) FORCE_SAVE_MODE="nosave"; shift ;;
    --out) OUT_PATH="${2:-}"; shift 2 ;;
    --threshold) THRESHOLD="${2:-}"; shift 2 ;;
    --dry-run) DRY_RUN=1; shift ;;
    --quiet) QUIET=1; shift ;;
    --stream) STREAM_MODE=1; shift ;;
    --no-stream) STREAM_MODE=0; shift ;;
    --json) OUTPUT_MODE="json"; shift ;;
    --pretty) OUTPUT_MODE="pretty"; shift ;;
    --text) OUTPUT_MODE="text"; shift ;;
    --raw) OUTPUT_MODE="raw"; shift ;;
    --chat) CHAT_MODE=1; shift ;;
    --show-config) SHOW_CONFIG=1; shift ;;
    --diagnostics) DIAGNOSTICS=1; shift ;;
    --provider)
      if [ "${2:-}" ] && [ "${2:0:1}" != "-" ]; then PROVIDER_CLI="${2:-}"; shift 2; else PROVIDER_INTERACTIVE=1; shift; fi
      ;;
    --install-extras)
      INSTALL_EXTRAS=1
      # optional explicit source: accept either "--install-extras <dir>" or "--install-extras=<dir>"
      if [ $# -gt 1 ] && [ "${2:0:1}" != "-" ]; then
        INSTALL_EXTRAS_SRC="${2:-}"
        shift
      fi
      shift
      ;;
    --install-extras=*)
      INSTALL_EXTRAS=1
      INSTALL_EXTRAS_SRC="${1#--install-extras=}"
      shift
      ;;
    --version) printf '%s %s (%s)\n' "$SCRIPT_NAME" "$SCRIPT_VERSION" "$SCRIPT_DATE"; exit 0 ;;
    -h|--help)
      help_file="$GROQBASH_EXTRAS_DIR/docs/help.txt"
      if [ -f "$help_file" ]; then cat "$help_file"; else printf 'Help file not found: %s\n' "$help_file" >&2; fi
      exit 0 ;;
    --bootstrap-only)
      BOOTSTRAP_ONLY=1
      shift
      ;;
    --) shift; break ;;
    -*) printf 'Unknown option: %s\n' "$1" >&2; exit "$GROQBASHERRTMP" ;;
    *) ARGS+=("$1"); shift ;;
  esac
done
